const resolveTracerouteRunStorageIDs = `-- name: ResolveTracerouteRunStorageIDs :one
SELECT probes.internal_id AS probe_storage_id,
       checks.internal_id AS check_storage_id
FROM probes
JOIN checks
    ON checks.project_id = probes.project_id
    AND checks.id = $1
    AND checks.check_type = 'traceroute'
    AND checks.deleted_at IS NULL
WHERE probes.project_id = $2
  AND probes.id = $3
  AND probes.deleted_at IS NULL
`

type ResolveTracerouteRunStorageIDsParams struct {
	CheckID   uuid.UUID `json:"check_id"`
	ProjectID uuid.UUID `json:"project_id"`
	ProbeID   uuid.UUID `json:"probe_id"`
}

type ResolveTracerouteRunStorageIDsRow struct {
	ProbeStorageID int64 `json:"probe_storage_id"`
	CheckStorageID int64 `json:"check_storage_id"`
}

func (q *Queries) ResolveTracerouteRunStorageIDs(ctx context.Context, arg ResolveTracerouteRunStorageIDsParams) (ResolveTracerouteRunStorageIDsRow, error) {
	row := q.db.QueryRow(ctx, resolveTracerouteRunStorageIDs, arg.CheckID, arg.ProjectID, arg.ProbeID)
	var i ResolveTracerouteRunStorageIDsRow
	err := row.Scan(&i.ProbeStorageID, &i.CheckStorageID)
	return i, err
}
